"use client";

import React, { useState } from "react";
import { MOCK_MENU, MenuItem } from "@/lib/mockPosData";
import { Terminal, ShoppingCart, ChevronRight } from "lucide-react";
import ProductModal from "./ProductModal";
import { useStore } from "@/store/StoreContext";
import CheckoutDrawer from "./CheckoutDrawer";

const CATEGORIES = ["All", "Coffee", "Tea", "Special", "Non-Coffee"];

export default function CustomerStorefront() {
  const [activeTab, setActiveTab] = useState("All");
  const [selectedProduct, setSelectedProduct] = useState<MenuItem | null>(null);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);

  const { cart, cartTotal } = useStore();

  const filteredMenu =
    activeTab === "All" ? MOCK_MENU : MOCK_MENU.filter((m) => m.category === activeTab);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-50 font-sans pb-24">
      {/* Header */}
      <header className="sticky top-0 z-20 bg-slate-950/80 backdrop-blur-md border-b border-slate-800 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Terminal className="text-cyan-400" size={24} />
          <h1 className="text-lg font-bold tracking-tight">Sudo Coffee<span className="text-cyan-400 text-xs ml-1 font-mono">_localhost</span></h1>
        </div>
      </header>

      {/* Categories */}
      <div className="overflow-x-auto whitespace-nowrap px-6 py-4 hide-scrollbar border-b border-slate-800/50">
        <div className="flex gap-3">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveTab(cat)}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${
                activeTab === cat
                  ? "bg-cyan-500 text-slate-950"
                  : "bg-slate-900 text-slate-400 hover:text-slate-200 border border-slate-800"
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Menu Grid */}
      <div className="p-6 grid grid-cols-2 gap-4">
        {filteredMenu.map((item) => (
          <div
            key={item.id}
            onClick={() => setSelectedProduct(item)}
            className="flex flex-col bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden cursor-pointer active:scale-95 transition-transform"
          >
            <div className={`h-32 w-full ${item.imageColor} flex items-center justify-center`}>
              {/* Optional: Add an icon or image here */}
            </div>
            <div className="p-3">
              <h3 className="font-semibold text-sm truncate">{item.name}</h3>
              <p className="text-cyan-400 font-mono text-sm mt-1">฿{item.price}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Floating Cart Button */}
      {cart.length > 0 && (
        <div className="fixed bottom-6 left-6 right-6 z-30">
          <button
            onClick={() => setIsCheckoutOpen(true)}
            className="w-full bg-cyan-500 text-slate-950 px-6 py-4 rounded-full font-bold shadow-lg shadow-cyan-500/20 flex items-center justify-between"
          >
            <div className="flex items-center gap-3">
              <div className="bg-slate-950 text-cyan-400 w-8 h-8 rounded-full flex items-center justify-center font-mono text-sm">
                {cart.reduce((s, i) => s + i.quantity, 0)}
              </div>
              <span className="tracking-wide">View Order</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="font-mono">฿{cartTotal}</span>
              <ChevronRight size={20} />
            </div>
          </button>
        </div>
      )}

      {/* Modals */}
      {selectedProduct && (
        <ProductModal
          product={selectedProduct}
          onClose={() => setSelectedProduct(null)}
        />
      )}

      {isCheckoutOpen && (
        <CheckoutDrawer onClose={() => setIsCheckoutOpen(false)} />
      )}
    </div>
  );
}

"use client";

import React from "react";
import { useStore, Order } from "@/store/StoreContext";
import { format } from "date-fns";
import { Clock, CheckCircle2, ChevronRight, Package, ArrowRight } from "lucide-react";

export default function OrderQueue() {
  const { orders, updateOrderStatus } = useStore();

  const pending = orders.filter((o) => o.status === "Pending");
  const making = orders.filter((o) => o.status === "Making");
  const done = orders.filter((o) => o.status === "Done").slice(0, 5); // Just show last 5 done

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-8rem)]">
      {/* Pending Column */}
      <div className="flex flex-col bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden">
        <div className="bg-slate-800/50 p-4 border-b border-slate-800 flex justify-between items-center">
          <h2 className="font-bold text-slate-100 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-cyan-500 animate-pulse" />
            Incoming queue
          </h2>
          <span className="bg-cyan-500 text-slate-950 font-mono text-xs px-2 py-1 rounded-full">{pending.length}</span>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {pending.length === 0 && <p className="text-slate-500 text-sm italic text-center py-8">No incoming orders</p>}
          {pending.map((order) => (
            <OrderCard key={order.id} order={order} nextAction={() => updateOrderStatus(order.id, "Making")} nextLabel="Start making" />
          ))}
        </div>
      </div>

      {/* Making Column */}
      <div className="flex flex-col bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden">
        <div className="bg-slate-800/50 p-4 border-b border-slate-800 flex justify-between items-center">
          <h2 className="font-bold text-slate-100 flex items-center gap-2">
            <Clock size={16} className="text-amber-500" />
            In progress
          </h2>
          <span className="bg-slate-800 text-amber-500 font-mono text-xs px-2 py-1 rounded-full border border-amber-500/20">{making.length}</span>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {making.length === 0 && <p className="text-slate-500 text-sm italic text-center py-8">Kitchen is clear</p>}
          {making.map((order) => (
            <OrderCard key={order.id} order={order} nextAction={() => updateOrderStatus(order.id, "Done")} nextLabel="Ready for pickup" isMaking />
          ))}
        </div>
      </div>

      {/* Done Column */}
      <div className="flex flex-col bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden opacity-80">
        <div className="bg-slate-800/50 p-4 border-b border-slate-800 flex justify-between items-center">
          <h2 className="font-bold text-slate-300 flex items-center gap-2">
            <CheckCircle2 size={16} className="text-emerald-500" />
            Completed
          </h2>
          <span className="font-mono text-xs text-slate-500">recent docs</span>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {done.length === 0 && <p className="text-slate-600 text-sm italic text-center py-8">Empty</p>}
          {done.map((order) => (
            <div key={order.id} className="bg-slate-950/50 p-4 rounded-xl border border-slate-800/50">
              <div className="flex justify-between items-start mb-2">
                <span className="font-mono text-slate-500 text-sm">#{order.id}</span>
                <span className="text-emerald-500 text-xs flex items-center gap-1"><CheckCircle2 size={12} /> fulfilled</span>
              </div>
              <p className="text-slate-400 text-sm">{order.items.length} items • ฿{order.totalPrice}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function OrderCard({ order, nextAction, nextLabel, isMaking = false }: { order: Order; nextAction: () => void; nextLabel: string; isMaking?: boolean }) {
  return (
    <div className={`p-4 rounded-xl border transition-colors ${
      isMaking ? "bg-amber-500/5 border-amber-500/20" : "bg-slate-950 border-slate-800 hover:border-cyan-500/50"
    }`}>
      <div className="flex justify-between items-start mb-4">
        <div>
          <h3 className={`font-mono font-bold ${isMaking ? "text-amber-400" : "text-cyan-400"}`}>#{order.id}</h3>
          <p className="text-slate-500 text-xs mt-1 flex items-center gap-1">
            <Clock size={12} /> {format(order.createdAt, "HH:mm:ss")} • {order.type}
          </p>
        </div>
        <div className="text-right">
          <span className="font-mono text-sm text-slate-300">฿{order.totalPrice}</span>
        </div>
      </div>

      <div className="space-y-3 mb-4">
        {order.items.map((item) => (
          <div key={item.id} className="flex gap-3 text-sm">
            <div className="bg-slate-900 border border-slate-800 text-slate-400 w-6 h-6 rounded flex items-center justify-center font-mono flex-shrink-0">
              {item.quantity}
            </div>
            <div>
              <p className="font-medium text-slate-200">{item.menuItem.name}</p>
              <p className="text-xs text-slate-500">{item.temperature} • {item.sweetness}</p>
              {item.addOns.length > 0 && (
                <p className="text-xs text-amber-500/80 italic mt-0.5">+ {item.addOns.map((a) => a.name.replace("+ ", "")).join(", ")}</p>
              )}
            </div>
          </div>
        ))}
      </div>

      <button
        onClick={nextAction}
        className={`w-full py-3 rounded-lg flex items-center justify-center gap-2 font-medium text-sm transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-950 ${
          isMaking 
            ? "bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 border border-emerald-500/20 focus:ring-emerald-500" 
            : "bg-cyan-500 text-slate-950 shadow-lg shadow-cyan-500/20 hover:bg-cyan-400 focus:ring-cyan-500"
        }`}
      >
        {nextLabel}
        {isMaking ? <CheckCircle2 size={16} /> : <ArrowRight size={16} />}
      </button>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { MenuItem, MOCK_ADDONS, AddOn } from "@/lib/mockPosData";
import { Sweetness, Temperature, useStore, CartItem } from "@/store/StoreContext";
import { X, Minus, Plus } from "lucide-react";

export default function ProductModal({ product, onClose }: { product: MenuItem; onClose: () => void }) {
  const { addToCart } = useStore();
  const [sweetness, setSweetness] = useState<Sweetness>("100%");
  const [temperature, setTemperature] = useState<Temperature>("Iced");
  const [selectedAddons, setSelectedAddons] = useState<Set<string>>(new Set());
  const [quantity, setQuantity] = useState(1);

  const toggleAddon = (id: string) => {
    setSelectedAddons((prev) => {
      const draft = new Set(prev);
      if (draft.has(id)) draft.delete(id);
      else draft.add(id);
      return draft;
    });
  };

  const calculateAddons = () => {
    return Array.from(selectedAddons).map((id) => MOCK_ADDONS.find((a) => a.id === id)!);
  };

  const addonTotal = calculateAddons().reduce((sum, a) => sum + a.price, 0);
  const totalItemPrice = product.price + addonTotal;
  const grandTotal = totalItemPrice * quantity;

  const handleConfirm = () => {
    const cartItem: CartItem = {
      id: `ci-${Date.now()}`,
      menuItem: product,
      sweetness,
      temperature,
      addOns: calculateAddons(),
      quantity,
      totalPrice: totalItemPrice,
    };
    addToCart(cartItem);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-950/80 backdrop-blur-sm flex items-end sm:items-center justify-center">
      <div className="bg-slate-900 border-t border-slate-800 sm:border rounded-t-3xl sm:rounded-2xl w-full max-w-md max-h-[90vh] overflow-y-auto overflow-x-hidden hide-scrollbar">
        {/* Header */}
        <div className="sticky top-0 bg-slate-900 z-10 p-6 border-b border-slate-800 flex justify-between items-center">
          <div>
            <h2 className="text-xl font-bold">{product.name}</h2>
            <p className="font-mono text-cyan-400 mt-1">฿{product.price}</p>
          </div>
          <button aria-label="Close" onClick={onClose} className="bg-slate-800 p-2 rounded-full text-slate-400 hover:text-white">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-6">
          {/* Temperature */}
          <section>
            <h3 className="font-semibold text-sm mb-3 text-slate-300">Temperature</h3>
            <div className="grid grid-cols-3 gap-3">
              {(["Hot", "Iced", "Frappe"] as Temperature[]).map((t) => (
                <button
                  key={t}
                  onClick={() => setTemperature(t)}
                  className={`py-2 rounded-xl text-sm font-medium border transition-colors ${
                    temperature === t
                      ? "border-cyan-500 bg-cyan-500/10 text-cyan-400"
                      : "border-slate-800 bg-slate-950 text-slate-400"
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </section>

          {/* Sweetness */}
          <section>
            <h3 className="font-semibold text-sm mb-3 text-slate-300">Sweetness Level</h3>
            <div className="grid grid-cols-4 gap-3">
              {(["0%", "50%", "100%", "120%"] as Sweetness[]).map((s) => (
                <button
                  key={s}
                  onClick={() => setSweetness(s)}
                  className={`py-2 rounded-xl text-sm font-medium border font-mono transition-colors ${
                    sweetness === s
                      ? "border-cyan-500 bg-cyan-500/10 text-cyan-400"
                      : "border-slate-800 bg-slate-950 text-slate-400"
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </section>

          {/* Add-ons */}
          <section>
            <h3 className="font-semibold text-sm mb-3 text-slate-300">Add-ons</h3>
            <div className="space-y-3">
              {MOCK_ADDONS.map((addon) => (
                <label key={addon.id} className="flex items-center justify-between bg-slate-950 p-4 rounded-xl border border-slate-800 cursor-pointer">
                  <div className="flex items-center gap-3">
                    <input
                      type="checkbox"
                      checked={selectedAddons.has(addon.id)}
                      onChange={() => toggleAddon(addon.id)}
                      className="w-5 h-5 rounded border-slate-700 text-cyan-500 focus:ring-cyan-500 focus:ring-offset-slate-950 bg-slate-900"
                    />
                    <span className="text-sm font-medium">{addon.name}</span>
                  </div>
                  <span className="font-mono text-slate-400 text-sm">+฿{addon.price}</span>
                </label>
              ))}
            </div>
          </section>

          {/* Quantity */}
          <section className="flex items-center justify-between py-2 border-t border-slate-800">
            <h3 className="font-semibold text-sm text-slate-300">Quantity</h3>
            <div className="flex items-center gap-4 bg-slate-950 p-2 rounded-full border border-slate-800">
              <button
                aria-label="Decrease quantity"
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
                className="bg-slate-900 p-2 rounded-full text-slate-400 hover:text-white"
              >
                <Minus size={16} />
              </button>
              <span className="font-mono font-bold w-4 text-center">{quantity}</span>
              <button
                aria-label="Increase quantity"
                onClick={() => setQuantity(quantity + 1)}
                className="bg-slate-900 p-2 rounded-full text-slate-400 hover:text-white"
              >
                <Plus size={16} />
              </button>
            </div>
          </section>
        </div>

        {/* Footer (Add to order) */}
        <div className="sticky bottom-0 bg-slate-900 p-6 border-t border-slate-800">
          <button
            onClick={handleConfirm}
            className="w-full bg-cyan-500 text-slate-950 font-bold py-4 rounded-full flex justify-between px-6 shadow-lg shadow-cyan-500/20"
          >
            <span>Add to Order</span>
            <span className="font-mono">฿{grandTotal.toLocaleString()}</span>
          </button>
        </div>
      </div>
    </div>
  );
}
